input.command:
PW=$(kubectl get secret admin-user-password -n mongodb -o jsonpath='{.data.password}' | base64 -d)
for p in 0 1 2; do
  echo "===== mongodb-replica-$p ====="
  kubectl exec -n mongodb mongodb-replica-$p -- mongosh --quiet "mongodb://admin-user:${PW}@localhost:27017/admin" --eval '
    var p = db.adminCommand({getCmdLineOpts:1}).parsed;
    print("verbosity        = " + p.systemLog.verbosity);
    print("slowOpThresholdMs= " + p.operationProfiling.slowOpThresholdMs);
    print("journalCompressor= " + p.storage.wiredTiger.engineConfig.journalCompressor);
    print("logLevel(runtime)= " + db.adminCommand({getParameter:1, logComponentVerbosity:1}).logComponentVerbosity.verbosity);
  ' 2>&1
done
echo "===== rs.status ====="
kubectl exec -n mongodb mongodb-replica-0 -- mongosh --quiet "mongodb://admin-user:${PW}@localhost:27017/admin" --eval 'rs.status().members.map(m=>m.name.split(".")[0]+":"+m.stateStr).join(", ")' 2>&1
